         $("#LoginUsernameId, #LoginPasswordId").on("keydown", function (evt) { if(evt.keyCode == 13) { $("#LoginForm").submit(); } }); <\/script>  ';

var regMessagePopupStyling = '

GET MORE FROM LFC 
Register or log in now to access FREE benefits 
Log in now, or register to access a range of FREE benefits including videos and exclusive competitions. 
 No thanks Yes, please!
